import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{n as i,r as a,t as o}from"./chunks/vm-arguments.BmU0TYdw.js";const s=JSON.parse(`{"title":"Запуск гри в IntelliJ IDEA","description":"Дізнайтеся, як використовувати різні профілі запуску, щоб запускати та налагоджувати свої моди в живому ігровому середовищі через IntelliJ IDEA.","frontmatter":{"title":"Запуск гри в IntelliJ IDEA","description":"Дізнайтеся, як використовувати різні профілі запуску, щоб запускати та налагоджувати свої моди в живому ігровому середовищі через IntelliJ IDEA.","authors":["IMB11","Tenneb22"],"prev":{"text":"Відкриття проєкту в IntelliJ IDEA","link":"./opening-a-project"},"next":{"text":"Генерація джерел в IntelliJ IDEA","link":"Генерація джерел"},"files":[]},"headers":[],"relativePath":"uk_ua/develop/getting-started/intellij-idea/launching-the-game.md","filePath":"translated/uk_ua/develop/getting-started/intellij-idea/launching-the-game.md","lastUpdated":1774518827000}`);var c={name:`uk_ua/develop/getting-started/intellij-idea/launching-the-game.md`};function l(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Запуск гри в IntelliJ IDEA <a class="header-anchor" href="#h1" aria-label="Permalink to “Запуск гри в IntelliJ IDEA”">​</a></h1><p>Fabric Loom надає різноманітні профілі запуску, які допоможуть вам запускати та налагоджувати моди в живому ігровому середовищі. Цей посібник охоплює різні профілі запуску та те, як їх використовувати для налагодження та тестування ваших модів.</p><h2 id="launch-profiles" tabindex="-1">Профілі запуску <a class="header-anchor" href="#launch-profiles" aria-label="Permalink to “Профілі запуску”">​</a></h2><p>Якщо ви використовуєте IntelliJ IDEA, ви можете знайти профілі запуску у верхньому правому куті вікна. Натисніть спадне меню, щоб переглянути доступні профілі запуску.</p><p>Повинен бути профіль клієнта та сервера з можливістю запуску у звичайному режимі або у режимі налагодження:</p><p><img src="/assets/develop/getting-started/launch-profiles.png" alt="Профілі запуску" loading="lazy"></p><h2 id="gradle-tasks" tabindex="-1">Завдання Gradle <a class="header-anchor" href="#gradle-tasks" aria-label="Permalink to “Завдання Gradle”">​</a></h2><p>Якщо ви використовуєте командний рядок, ви можете використовувати такі команди Gradle, щоб запустити гру:</p><ul><li><code>./gradlew runClient</code> — запускає гру в режимі клієнта.</li><li><code>./gradlew runServer</code> — запустити гру в режимі сервера.</li></ul><p>Єдина проблема цього підходу полягає в тому, що ви не можете легко налагодити свій код. Якщо ви хочете налагодити свій код, вам потрібно буде використовувати профілі запуску в IntelliJ IDEA або через інтеграцію Gradle в IDE.</p><h2 id="hotswapping-classes" tabindex="-1">Класи гарячої заміни <a class="header-anchor" href="#hotswapping-classes" aria-label="Permalink to “Класи гарячої заміни”">​</a></h2><p>Коли ви запускаєте гру в режимі налагодження, ви можете гаряче замінити свої класи, не перезапускаючи гру. Це корисно для швидкого тестування змін у вашому коді.</p><p>Однак ви все ще досить обмежені:</p><ul><li>Ви не можете додавати або видаляти методи</li><li>Ви не можете змінити параметри методу</li><li>Ви не можете додати або видалити поля</li></ul><p>Однак, використовуючи <a href="https://github.com/JetBrains/JetBrainsRuntime" target="_blank" rel="noreferrer">JetBrains Runtime</a>, ви можете обійти більшість обмежень і навіть додавати або видаляти класи та методи. Це дозволить більшості змін набрати чинності без перезапуску гри.</p><p>Не забудьте додати наступне до параметра VM Arguments у ваших налаштуваннях запуску Minecraft:</p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>-XX:+AllowEnhancedClassRedefinition</span></span></code></pre></div><h2 id="hotswapping-mixins" tabindex="-1">Міксини гарячої заміни <a class="header-anchor" href="#hotswapping-mixins" aria-label="Permalink to “Міксини гарячої заміни”">​</a></h2><p>Якщо ви використовуєте міксини, ви можете використовувати гарячу заміну своїх класів міксинів, не перезапускаючи гру. Це корисно для швидкого тестування змін у ваших міксинах.</p><p>Однак вам потрібно буде встановити агент Mixin Java, щоб це працювало.</p><h3 id="1-locate-the-mixin-library-jar" tabindex="-1">1. Знайдіть Mixin Library Jar <a class="header-anchor" href="#1-locate-the-mixin-library-jar" aria-label="Permalink to “1. Знайдіть Mixin Library Jar”">​</a></h3><p>У IntelliJ IDEA ви можете знайти Mixin Library Jar в розділі «External Libraries» розділу «Project»:</p><p><img src="/assets/develop/getting-started/mixin-library.png" alt="Mixin Library" loading="lazy"></p><p>Вам потрібно буде скопіювати «Absolute Path» банки для наступного кроку.</p><h3 id="2-add-the--javaagent-vm-argument" tabindex="-1">2. Додайте аргумент віртуальної машини <code>-javaagent</code> <a class="header-anchor" href="#2-add-the--javaagent-vm-argument" aria-label="Permalink to “2. Додайте аргумент віртуальної машини -javaagent”">​</a></h3><p>У налаштуваннях запуску «Клієнта Minecraft» і/або «Сервера Minecraft» додайте наступне до параметра «VM Arguments»:</p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>-javaagent:&quot;path to mixin library jar here&quot;</span></span></code></pre></div><p><img src="/assets/develop/getting-started/vm-arguments.png" alt="Знімок екрана VM Arguments" loading="lazy"></p><p>Тепер ви зможете змінювати вміст ваших методів міксинів під час налагодження, і зміни набудуть чинності без перезапуску гри.</p>`,29)]])}var u=r(c,[[`render`,l]]);export{s as __pageData,u as default};